"""Authoritative Stage 7 Institutional Copilot validation fixtures.

The fixtures describe inputs and observable contract expectations.  They do
not contain fabricated market values and are intentionally independent of the
Copilot runtime so the artifact generator can run before application startup.
"""

from __future__ import annotations

from copy import deepcopy
from typing import Any


FIXTURE_SCHEMA_VERSION = "stage7-copilot-fixture-v1"
MANIFEST_SCHEMA_VERSION = "stage7-copilot-fixture-manifest-v1"


def _action(
    destination: str,
    route: str,
    *,
    tab: str | None = None,
    sub_tab: str | None = None,
    section_id: str | None = None,
    entity: str | None = None,
    highlight_target: str | None = None,
) -> dict[str, Any]:
    return {
        "destination": destination,
        "route": route,
        "tab": tab,
        "subTab": sub_tab,
        "sectionId": section_id,
        "entity": entity,
        "highlightTarget": highlight_target,
    }


def _entity(entity_type: str, entity_id: str) -> dict[str, str]:
    return {"type": entity_type, "id": entity_id}


def _fixture(
    ordinal: int,
    case_id: str,
    title: str,
    prompt: str,
    intent: str,
    required_agents: tuple[str, ...],
    *,
    optional_agents: tuple[str, ...] = (),
    entities: tuple[dict[str, str], ...] = (),
    context: dict[str, Any] | None = None,
    session_context: dict[str, Any] | None = None,
    inherited_intent: str | None = None,
    ambiguity: str = "none",
    allowed_statuses: tuple[str, ...] = ("complete",),
    expected_freshness: tuple[str, ...] = ("cached", "delayed", "live"),
    actions: tuple[dict[str, Any], ...] = (),
    challenge_mode: bool = False,
    data_scenario: str = "durable-cached",
    trace_scenario: str = "normal",
    required_response_text: tuple[str, ...] = (),
    forbidden_response_text: tuple[str, ...] = (),
    assertions: tuple[str, ...] = (),
) -> dict[str, Any]:
    return {
        "schemaVersion": FIXTURE_SCHEMA_VERSION,
        "ordinal": ordinal,
        "caseId": case_id,
        "title": title,
        "request": {
            "message": prompt,
            "context": deepcopy(context or {"screenType": "general", "routeName": "/ai"}),
            "sessionContext": deepcopy(session_context),
        },
        "dataScenario": data_scenario,
        "traceScenario": trace_scenario,
        "expected": {
            "intent": intent,
            "inheritedIntent": inherited_intent,
            "requiredAgents": list(required_agents),
            "optionalAgents": list(optional_agents),
            "entities": [dict(item) for item in entities],
            "ambiguity": ambiguity,
            "allowedResponseStatuses": list(allowed_statuses),
            "allowedFreshnessStates": list(expected_freshness),
            "challengeMode": challenge_mode,
            "actions": [dict(item) for item in actions],
            "requiredResponseText": list(required_response_text),
            "forbiddenResponseText": list(forbidden_response_text),
            "assertions": list(assertions),
        },
    }


